function _raiseToPower(
    uint256 base_,
    uint256 exponent_
) internal pure returns (uint256 result_) {
    result_ = exponent_ & 1 == 0 ? PRECISION : base_;

    while ((exponent_ >>= 1) > 0) {
        base_ = Math.mulDiv(base_, base_, PRECISION);

        if (exponent_ & 1 == 1) {
            result_ = Math.mulDiv(result_, base_, PRECISION);
        }
    }
}
